output.sparql:
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?manager ?managerLabel WHERE {
  wd:Q18721 p:P1815 ?manager_statement .
  ?manager_statement ps:P1815 ?manager .
  ?manager_statement pq:P580 ?start .
  OPTIONAL {
    ?manager_statement pq:P582 ?end
  }
  FILTER(?start <= "2021-05-23" ^^ xsd:date &&(! BOUND(?end) || ?end >= "2021-05-23" ^^ xsd:date))
  OPTIONAL {
    ?manager rdfs:label ?managerLabel .
    FILTER(LANG(?managerLabel) = "en")
  }
}
